From 0e10d9f6fb2222d07db403ffccdb827070acea9d Mon Sep 17 00:00:00 2001
From: Mat Groves <mat.groves@play.co>
Date: Fri, 24 Jan 2025 19:09:11 +0000
Subject: [PATCH 1/3] match uv size if non is provided

---
 src/scene/mesh/shared/MeshGeometry.ts | 16 +++++++++++++++-
 1 file changed, 15 insertions(+), 1 deletion(-)

diff --git a/src/scene/mesh/shared/MeshGeometry.ts b/src/scene/mesh/shared/MeshGeometry.ts
index 6824620edcc..a939718c405 100644
--- a/src/scene/mesh/shared/MeshGeometry.ts
+++ b/src/scene/mesh/shared/MeshGeometry.ts
@@ -63,7 +63,21 @@ export class MeshGeometry extends Geometry
         options = { ...MeshGeometry.defaultOptions, ...options };

         const positions = options.positions || new Float32Array([0, 0, 1, 0, 1, 1, 0, 1]);
-        const uvs = options.uvs || new Float32Array([0, 0, 1, 0, 1, 1, 0, 1]);
+
+        let uvs = options.uvs;
+
+        if (!uvs)
+        {
+            if (options.positions)
+            {
+                uvs = new Float32Array(positions.length);
+            }
+            else
+            {
+                uvs = new Float32Array([0, 0, 1, 0, 1, 1, 0, 1]);
+            }
+        }
+
         const indices = options.indices || new Uint32Array([0, 1, 2, 0, 2, 3]);

         const shrinkToFit = options.shrinkBuffersToFit;

